import{_ as o,C as n,o as l,c as s,E as i,w as a,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const k=JSON.parse('{"title":"Moving to Iceland","description":"Immigration pathways and relocation guide for Iceland","frontmatter":{"layout":"doc","title":"Moving to Iceland","description":"Immigration pathways and relocation guide for Iceland"},"headers":[],"relativePath":"europe/iceland/moving-there.md","filePath":"europe/iceland/moving-there.md","lastUpdated":1780522877000}'),h={name:"europe/iceland/moving-there.md"};function c(m,t,g,u,f,p){const e=n("Badge");return l(),s("div",null,[i(e,{variant:"green"},{default:a(()=>[...t[0]||(t[0]=[r("EEA: Free Movement",-1)])]),_:1}),i(e,{variant:"yellow"},{default:a(()=>[...t[1]||(t[1]=[r("UK: Visa-free 6 months",-1)])]),_:1}),i(e,{variant:"blue"},{default:a(()=>[...t[2]||(t[2]=[r("Remote Work Visa Available",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="moving-to-iceland" tabindex="-1">Moving to Iceland <a class="header-anchor" href="#moving-to-iceland" aria-label="Permalink to &quot;Moving to Iceland&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><ul><li><strong>Free movement rights</strong> — no visa required</li><li><strong>Up to 3 months</strong>: No registration needed</li><li><strong>Over 3 months</strong>: Must register with Registers Iceland</li><li><strong>Right to work</strong>: Automatic, no work permit needed</li></ul><h3 id="uk-citizens-post-brexit" tabindex="-1">UK Citizens (Post-Brexit) <a class="header-anchor" href="#uk-citizens-post-brexit" aria-label="Permalink to &quot;UK Citizens (Post-Brexit)&quot;">​</a></h3><ul><li><strong>Visa-free</strong>: Up to 6 months for tourism/short stays</li><li><strong>Longer stays</strong>: Apply for residence permit: <ul><li>Work permit (requires job offer)</li><li>Study permit (accepted to accredited institution)</li><li>Family reunification</li></ul></li></ul><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><ul><li><strong>Visas Required</strong>: Yes — apply through Directorate of Immigration</li><li><strong>Options include</strong>:<table tabindex="0"><thead><tr><th>Visa Type</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Permit</td><td>Job offer from Icelandic employer</td><td>Up to 2 years, renewable</td></tr><tr><td>Student Visa</td><td>Enrollment at accredited institution</td><td>Duration of studies</td></tr><tr><td>Remote Work Visa</td><td>Remote employment, min income requirements</td><td>Up to 18 months</td></tr><tr><td>Family Reunification</td><td>Family ties to Icelandic resident</td><td>Permanent</td></tr><tr><td>Start-up Visa</td><td>Innovative business plan, funding secured</td><td>Up to 2 years</td></tr></tbody></table></li></ul><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Iceland offers a <strong>long-term visa for remote workers</strong>:</p><ul><li>Valid for up to <strong>18 months</strong></li><li>Requirements: Remote employment with income above threshold (~1,000,000 ISK/month)</li><li>Cannot be extended beyond 18 months</li><li>Good option for testing living in Iceland before committing</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for at least 6 months</li><li>[ ] <strong>Visa</strong>: Check requirements for your nationality</li><li>[ ] <strong>Healthcare</strong>: Research health insurance options</li><li>[ ] <strong>HRT</strong>: Get 3-6 month supply and doctor&#39;s letter</li><li>[ ] <strong>Banking</strong>: Set up international banking options</li><li>[ ] <strong>Housing</strong>: Research rental market (reykjavikrent.is)</li><li>[ ] <strong>Language</strong>: Basic Icelandic helpful; English widely spoken</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register with Registers Iceland (EEA citizens: after 3 months)</li><li>[ ] Apply for kennitala (Icelandic ID number)</li><li>[ ] Register with healthcare system</li><li>[ ] Open local bank account</li><li>[ ] Get Icelandic phone number</li><li>[ ] Connect with LGBTQ+ community (Trans Iceland, Samtökin &#39;78)</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li><strong>High</strong> — especially housing in Reykjavík</li><li>Monthly rent (1-bed apartment): 150,000-250,000 ISK</li><li>Monthly groceries: 50,000-80,000 ISK</li><li>Public transport: 6,000-10,000 ISK/month</li></ul><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Winters</strong>: Cold (0°C to -10°C), dark (4-5 hours daylight)</li><li><strong>Summers</strong>: Mild (10°C to 15°C), midnight sun</li><li><strong>Best time to arrive</strong>: Late spring/summer (May-August)</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li>Official language: Icelandic</li><li>English: Widely spoken, especially in Reykjavík</li><li>Icelandic courses available for immigrants</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.utl.is/" target="_blank" rel="noreferrer">Directorate of Immigration (Útlendingastofnun)</a></li><li><a href="https://www.skra.is/" target="_blank" rel="noreferrer">Registers Iceland</a></li><li><a href="https://www.iceland.is/move-to-iceland/" target="_blank" rel="noreferrer">Iceland.is - Moving to Iceland</a></li><li><a href="https://trans.is/" target="_blank" rel="noreferrer">Trans Iceland</a></li><li><a href="https://samtokin78.is/" target="_blank" rel="noreferrer">Reykjavík LGBTQ+ Center</a></li></ul>',25))])}const v=o(h,[["render",c]]);export{k as __pageData,v as default};
